class Solution:
    def queensAttacktheKing(self, queens, king):
        qs = set((x, y) for x, y in queens)
        kx, ky = king
        res = []
        for dx in (-1, 0, 1):
            for dy in (-1, 0, 1):
                if dx == 0 and dy == 0:
                    continue
                x, y = kx + dx, ky + dy
                while 0 <= x < 8 and 0 <= y < 8:
                    if (x, y) in qs:
                        res.append([x, y])
                        break
                    x += dx
                    y += dy
        return res

