class Solution:
    def queensAttacktheKing(self, queens, king):
        board = [[False] * 8 for _ in range(8)]
        for x, y in queens:
            board[x][y] = True
        kx, ky = king
        res = []
        for dx in (-1, 0, 1):
            for dy in (-1, 0, 1):
                if dx == 0 and dy == 0:
                    continue
                x, y = kx + dx, ky + dy
                while 0 <= x < 8 and 0 <= y < 8:
                    if board[x][y]:
                        res.append([x, y])
                        break
                    x += dx
                    y += dy
        return res

